# Gear SPC API v9 wrapper.
# Calls the already-running FastAPI backend and returns pure spc_result JSON.
def _loads_or_none(value):
    value = str(value or "").strip()
    if not value:
        return None
    return json.loads(value)

csv_text = str(globals().get("input_text", "") or "").strip()
input_files = globals().get("input_files", []) or []
if not csv_text:
    for raw_path in input_files:
        path = pathlib.Path(str(raw_path))
        if path.exists() and path.suffix.lower() == ".csv":
            for encoding in ("utf-8-sig", "utf-8", "gbk"):
                try:
                    csv_text = path.read_text(encoding=encoding)
                    break
                except UnicodeDecodeError:
                    continue
        if csv_text:
            break

payload = {
    "csv": csv_text,
    "specs": _loads_or_none(globals().get("specs_json", "")),
    "config": _loads_or_none(globals().get("config_json", "")),
}

response = requests.post(
    str(globals().get("api_url", "http://127.0.0.1:8000")).rstrip("/") + "/analyze",
    json=payload,
    timeout=120,
)
response.raise_for_status()
api_result = response.json()
print(json.dumps(api_result.get("spc_result") or api_result, ensure_ascii=False))
